// VPN service layer — wraps libopenlawsvpn FFI in an async Tokio task.
// Communicates with the UI via futures_channel::mpsc:
//   - service thread sends via UnboundedSender (Send + 'static)
//   - main.rs polls the UnboundedReceiver with glib::spawn_future_local,
//     which runs on glib's own async executor (no tokio waker needed)

use std::ffi::{CStr, CString};
use std::sync::{Arc, Mutex};

use futures_channel::mpsc::{self, UnboundedReceiver, UnboundedSender};

// FFI bindings generated by bindgen in build.rs
#[allow(non_upper_case_globals, non_camel_case_types, non_snake_case, dead_code)]
mod ffi {
    include!(concat!(env!("OUT_DIR"), "/bindings.rs"));
}

#[derive(Debug, Clone)]
pub enum VpnEvent {
    StateChanged(VpnState),
    LogLine(String),
}

#[derive(Debug, Clone, PartialEq)]
pub enum VpnState {
    Idle,
    Connecting,
    WaitingSaml { saml_url: String },
    Connected { server_ip: String, assigned_ip: String },
    Disconnecting,
    NeedReauth,
    Error(String),
}

#[derive(Debug)]
pub enum VpnCommand {
    Connect { config_path: String },
    Disconnect,
}

pub struct VpnService {
    pub cmd_tx: tokio::sync::mpsc::Sender<VpnCommand>,
    /// Holds the futures_channel receiver until the caller takes it with `take_event_rx()`.
    /// Must be taken exactly once from the GTK main thread before the first event arrives.
    event_rx: std::cell::RefCell<Option<UnboundedReceiver<VpnEvent>>>,
}

impl VpnService {
    pub fn new() -> Self {
        let (cmd_tx, cmd_rx) = tokio::sync::mpsc::channel::<VpnCommand>(8);
        let (event_tx, event_rx) = mpsc::unbounded::<VpnEvent>();

        std::thread::spawn(move || {
            service_thread(cmd_rx, event_tx);
        });

        Self {
            cmd_tx,
            event_rx: std::cell::RefCell::new(Some(event_rx)),
        }
    }

    /// Take the event receiver so it can be polled in glib::spawn_future_local.
    /// Panics if called more than once.
    pub fn take_event_rx(&self) -> UnboundedReceiver<VpnEvent> {
        self.event_rx
            .borrow_mut()
            .take()
            .expect("take_event_rx() called more than once")
    }
}

// Safety wrapper: libopenlawsvpn client pointer is used from a single
// dedicated thread, protected by Mutex. Marking Send is safe here.
struct ClientPtr(*mut std::ffi::c_void);
unsafe impl Send for ClientPtr {}

// Runs on a dedicated OS thread (not async) because libopenlawsvpn blocks.
fn service_thread(
    mut cmd_rx: tokio::sync::mpsc::Receiver<VpnCommand>,
    event_tx: UnboundedSender<VpnEvent>,
) {
    let rt = tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build()
        .expect("tokio rt");

    rt.block_on(async move {
        let client: Arc<Mutex<Option<ClientPtr>>> = Arc::new(Mutex::new(None));

        while let Some(cmd) = cmd_rx.recv().await {
            match cmd {
                VpnCommand::Connect { config_path } => {
                    let event_tx = event_tx.clone();
                    let client = client.clone();
                    let config_path_clone = config_path.clone();

                    // Phase 1 runs in a blocking thread
                    let handle = tokio::task::spawn_blocking(move || {
                        let c_path = CString::new(config_path_clone).unwrap();
                        let ptr = unsafe { ffi::openvpn_client_new(c_path.as_ptr()) };

                        // Log callback — sends log lines to UI via event channel
                        let tx_log = event_tx.clone();
                        unsafe {
                            ffi::openvpn_client_set_log_callback(
                                ptr,
                                Some(log_callback),
                                Box::into_raw(Box::new(tx_log)) as *mut _,
                            );
                            // D-Bus mode (1 = DBUS)
                            ffi::openvpn_client_set_connect_mode(ptr, 1);
                        }

                        // Store pointer for later use
                        *client.lock().unwrap() = Some(ClientPtr(ptr));

                        emit(&event_tx, VpnEvent::StateChanged(VpnState::Connecting));

                        let result = unsafe { ffi::openvpn_client_connect_phase1(ptr) };

                        // Extract strings before checking — always free to avoid leaks
                        let saml_url = if result.saml_url.is_null() { String::new() } else {
                            unsafe { CStr::from_ptr(result.saml_url).to_string_lossy().into_owned() }
                        };
                        let state_id = if result.state_id.is_null() { String::new() } else {
                            unsafe { CStr::from_ptr(result.state_id).to_string_lossy().into_owned() }
                        };
                        let remote_ip = if result.remote_ip.is_null() { String::new() } else {
                            unsafe { CStr::from_ptr(result.remote_ip).to_string_lossy().into_owned() }
                        };
                        unsafe {
                            if !result.saml_url.is_null() { ffi::openvpn_free_string(result.saml_url); }
                            if !result.state_id.is_null() { ffi::openvpn_free_string(result.state_id); }
                            if !result.remote_ip.is_null() { ffi::openvpn_free_string(result.remote_ip); }
                        }

                        // Validate: a real Phase 1 result has a non-empty SAML URL and state_id
                        if saml_url.is_empty() || state_id.is_empty() {
                            emit(&event_tx, VpnEvent::StateChanged(
                                VpnState::Error("Phase 1 failed — check openvpn3 D-Bus services are running".into()),
                            ));
                            return;
                        }

                        // Open browser and start SAML capture server
                        std::process::Command::new("xdg-open").arg(&saml_url).spawn().ok();

                        emit(&event_tx, VpnEvent::StateChanged(VpnState::WaitingSaml {
                            saml_url: saml_url.clone(),
                        }));

                        // Start SAML capture server — blocks until token received or timeout
                        let token = match crate::saml_server::capture_saml_token(120) {
                            Ok(t) => t,
                            Err(e) => {
                                emit(&event_tx, VpnEvent::StateChanged(
                                    VpnState::Error(format!("SAML login failed: {}", e)),
                                ));
                                return;
                            }
                        };

                        // Phase 2 — send CRV1 token; tunnel comes up asynchronously via D-Bus signals.
                        // We emit Connecting again while waiting; Connected is emitted when
                        // the log callback sees "tunnel is up" (log-driven state machine).
                        emit(&event_tx, VpnEvent::StateChanged(VpnState::Connecting));

                        let c_state = CString::new(state_id).unwrap();
                        let c_token = CString::new(token).unwrap();
                        let c_remote = CString::new(remote_ip).unwrap();
                        let raw_ptr = client.lock().unwrap().as_ref().map(|p| p.0);
                        if let Some(p) = raw_ptr {
                            unsafe {
                                ffi::openvpn_client_connect_phase2(
                                    p,
                                    c_state.as_ptr(),
                                    c_token.as_ptr(),
                                    c_remote.as_ptr(),
                                );
                            }
                        } else {
                            emit(&event_tx, VpnEvent::StateChanged(
                                VpnState::Error("Client pointer lost before Phase 2".into()),
                            ));
                            return;
                        }

                        // Phase 2 is void — success/failure is determined by the log stream.
                        // The log callback drives state transitions based on log content.
                        // We do NOT emit Connected here.
                    });

                    let _ = handle.await;
                }

                VpnCommand::Disconnect => {
                    let client = client.clone();
                    let event_tx = event_tx.clone();
                    tokio::task::spawn_blocking(move || {
                        emit(&event_tx, VpnEvent::StateChanged(VpnState::Disconnecting));
                        let mut guard = client.lock().unwrap();
                        if let Some(ClientPtr(ptr)) = guard.take() {
                            unsafe {
                                ffi::openvpn_client_disconnect(ptr);
                                ffi::openvpn_client_free(ptr);
                            }
                        }
                        emit(&event_tx, VpnEvent::LogLine("Disconnected.".into()));
                        emit(&event_tx, VpnEvent::StateChanged(VpnState::Idle));
                    })
                    .await
                    .ok();
                }

            }
        }
    });
}

fn emit(tx: &UnboundedSender<VpnEvent>, event: VpnEvent) {
    tx.unbounded_send(event).ok();
}

// C-callable log callback — forwards lines to the futures_channel and
// drives state transitions by inspecting the log content.
unsafe extern "C" fn log_callback(message: *const std::ffi::c_char, user_data: *mut std::ffi::c_void) {
    if message.is_null() || user_data.is_null() {
        return;
    }
    let msg = unsafe { CStr::from_ptr(message).to_string_lossy().into_owned() };
    let tx = unsafe {
        &*(user_data as *const UnboundedSender<VpnEvent>)
    };

    // Forward raw log line to UI
    tx.unbounded_send(VpnEvent::LogLine(msg.trim_end().to_string())).ok();

    // Detect tunnel up/down/error from well-known log patterns
    let lower = msg.to_lowercase();
    if lower.contains("connected to") || lower.contains("tunnel is up") {
        tx.unbounded_send(VpnEvent::StateChanged(VpnState::Connected {
            server_ip: String::new(),
            assigned_ip: String::new(),
        })).ok();
    } else if lower.contains("connectphase2 error") || lower.contains("auth_failed") || lower.contains("authentication failed") {
        let detail = msg
            .find("ERROR:")
            .map(|i| msg[i + 6..].trim().to_string())
            .unwrap_or_else(|| msg.trim().to_string());
        tx.unbounded_send(VpnEvent::StateChanged(VpnState::Error(detail))).ok();
    } else if lower.contains("need_creds") || lower.contains("session expired") {
        tx.unbounded_send(VpnEvent::StateChanged(VpnState::NeedReauth)).ok();
    } else if lower.contains("disconnected") || lower.contains("tunnel is down") {
        tx.unbounded_send(VpnEvent::StateChanged(VpnState::Idle)).ok();
    }
}
